module top_module(datain, dataout, clk, clr, WE);input [31:0] datain;
    output [31:0] dataout;
    input clk, clr, WE;

    reg [31:0] register;

  wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge clk or posedge clr or posedge dbg_halt)
begin
  if(clr)
    register = 0;  
  else
    if(WE == 1)
    register =  datain;
end    
  assign dataout = register;

endmodule
